const res = $input.first().json;

if (!res.content) {
  return [{ json: { resumen: 'Sin piezas registradas en el tracker.', stats: {}, trackerSha: null, trackerBase64: null } }];
}

let tracker = {};
try { tracker = JSON.parse(Buffer.from(res.content, 'base64').toString('utf8')); } catch(e) {}
const trackerSha = res.sha || null;

const piezas = Object.keys(tracker);
const ahora = new Date();
const stats = { total: piezas.length, por_estado: {}, bloqueadas_48h: [] };

for (const p of piezas) {
  const estado = tracker[p].estado_actual || 'DESCONOCIDO';
