  }
}

const dateStr = ahora.toISOString().split('T')[0];
let resumen = `📊 *PIPELINE STATUS — ${dateStr}*\n\nTotal piezas: ${stats.total}\n\n*Por estado:*\n`;
for (const [estado, count] of Object.entries(stats.por_estado)) resumen += `  • ${estado}: ${count}\n`;
if (stats.bloqueadas_48h.length > 0) {
  resumen += `\n⚠️ *Bloqueadas >48h:*\n`;
  for (const b of stats.bloqueadas_48h) resumen += `  • ${b}\n`;
} else {
  resumen += `\n✅ Sin piezas bloqueadas.\n`;
}

return [{ json: { resumen, stats, trackerSha } }];

const logRes = $input.first().json;
const stats = $('Calcular Estadísticas').first().json.stats;
const today = new Date().toISOString().split('T')[0];
const time = new Date().toISOString().split('T')[1].substring(0, 5);
const logLine = `| ${today} | ${time} | DAILY_STATUS | — | Total: ${stats.total || 0}, Bloqueadas: ${(stats.bloqueadas_48h || []).length} |`;

let existing = '';
let sha = null;
if (logRes.content) {
  existing = Buffer.from(logRes.content, 'base64').toString('utf8');
  sha = logRes.sha || null;
} else {
  existing = '# FG Operations Log\n\n| Fecha | Hora | Evento | Pieza | Detalles |\n|-------|------|--------|-------|----------|\n';
}

const updated = existing + logLine + '\n';
const base64Content = Buffer.from(updated).toString('base64');
return [{ json: { base64Content, ...(sha ? { sha } : {}) } }];
